import React, { useState, useEffect } from 'react';
import { PageBanner, NavPills, ScoreCard, SvgGauge, SectionHeader, DataTable, Spinner, Footer } from '../components/UIComponents';
import { getMaturityQuestions, submitMaturity, downloadMaturityExcel, downloadMaturityPDF } from '../utils/api';

const DEFAULT_OBJECTS = ['Customer', 'Vendor Master', 'Item Master', 'Price', 'Finance'];

// Rating options: the VALUES sent to backend are the numeric strings.
// The backend converts "1" → "Adhoc", "2" → "Repeatable", etc.
const RATING_OPTIONS = [
  { label: '1 - Adhoc', value: '1' },
  { label: '2 - Repeatable', value: '2' },
  { label: '3 - Defined', value: '3' },
  { label: '4 - Managed', value: '4' },
  { label: '5 - Optimised', value: '5' },
];

export default function MaturityPage({ onNavigate, sessionId, dqScore }) {
  const [clientName, setClientName] = useState('');
  const [objects, setObjects] = useState([...DEFAULT_OBJECTS]);
  const [dims, setDims] = useState([]);
  // questions: { "Data Governance": [ {id, section, question, weight}, ... ] }
  const [questions, setQuestions] = useState({});
  // responses: { "Data Governance": [ {Question: "...", "Question ID": "DG-1", Section: "...", Weight: 2, Customer: "3", ...} ] }
  const [responses, setResponses] = useState({});
  const [benchmark, setBenchmark] = useState(3.0);
  const [target, setTarget] = useState(3.0);
  const [lowThr, setLowThr] = useState(2.0);
  const [mastersApplicable, setMastersApplicable] = useState(true);

  const [loading, setLoading] = useState(false);
  const [submitted, setSubmitted] = useState(false);
  const [results, setResults] = useState(null);
  const [error, setError] = useState('');
  const [activeDim, setActiveDim] = useState(null);

  // Load questions on mount
  useEffect(() => {
    loadQuestions();
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []);

  const loadQuestions = async () => {
    try {
      const resp = await getMaturityQuestions([], []);
      const qData = resp.data.questions || {};
      const dimList = Object.keys(qData);

      setQuestions(qData);
      setDims(dimList);
      if (dimList.length > 0) setActiveDim(dimList[0]);

      // Initialize responses with structured rows
      const initResp = {};
      Object.entries(qData).forEach(([dim, qList]) => {
        initResp[dim] = qList.map((q) => {
          const row = {
            'Question': q.question,
            'Question ID': q.id,
            'Section': q.section,
            'Weight': q.weight || 1,
          };
          // Initialize each object column to empty (no rating selected yet)
          objects.forEach((obj) => { row[obj] = ''; });
          return row;
        });
      });
      setResponses(initResp);
    } catch (e) {
      setError('Failed to load questions: ' + (e.response?.data?.error || e.message));
    }
  };

  // Update a single response cell
  const updateResponse = (dim, qIdx, obj, value) => {
    setResponses((prev) => {
      const updated = { ...prev };
      const rows = [...(updated[dim] || [])];
      rows[qIdx] = { ...rows[qIdx], [obj]: value };
      updated[dim] = rows;
      return updated;
    });
  };

  // Submit assessment
  const handleSubmit = async () => {
    if (!clientName.trim()) {
      setError('Please enter a Client Name in the sidebar.');
      return;
    }

    // Check at least some responses are filled
    let hasAnyResponse = false;
    for (const dim of dims) {
      for (const row of (responses[dim] || [])) {
        for (const obj of currentObjects) {
          if (row[obj] && row[obj] !== '') {
            hasAnyResponse = true;
            break;
          }
        }
        if (hasAnyResponse) break;
      }
      if (hasAnyResponse) break;
    }

    if (!hasAnyResponse) {
      setError('Please fill in at least some ratings before submitting.');
      return;
    }

    setLoading(true);
    setError('');
    try {
      const resp = await submitMaturity({
        session_id: sessionId,
        client_name: clientName,
        dims,
        objects: currentObjects,
        responses,
        benchmark,
        target,
        low_thr: lowThr,
        dq_score: dqScore,
      });
      setResults(resp.data);
      setSubmitted(true);
    } catch (e) {
      setError(e.response?.data?.error || e.message);
    } finally {
      setLoading(false);
    }
  };

  const currentObjects = mastersApplicable ? objects : [clientName || 'Overall'];

  // When objects change, update response rows to include new object columns
  useEffect(() => {
    setResponses((prev) => {
      const updated = { ...prev };
      Object.keys(updated).forEach((dim) => {
        updated[dim] = (updated[dim] || []).map((row) => {
          const newRow = { ...row };
          currentObjects.forEach((obj) => {
            if (!(obj in newRow)) newRow[obj] = '';
          });
          return newRow;
        });
      });
      return updated;
    });
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [objects, mastersApplicable, clientName]);

  // Group questions by section for display
  const getGroupedQuestions = (dim) => {
    const qList = questions[dim] || [];
    const groups = [];
    let currentSection = null;
    let currentGroup = null;

    qList.forEach((q, idx) => {
      if (q.section !== currentSection) {
        currentSection = q.section;
        currentGroup = { section: q.section, questions: [] };
        groups.push(currentGroup);
      }
      currentGroup.questions.push({ ...q, originalIndex: idx });
    });

    return groups;
  };

  // Count filled responses for a dimension
  const countFilled = (dim) => {
    const rows = responses[dim] || [];
    let filled = 0;
    let total = 0;
    rows.forEach((row) => {
      currentObjects.forEach((obj) => {
        total++;
        if (row[obj] && row[obj] !== '') filled++;
      });
    });
    return { filled, total };
  };

  return (
    <div className="page-maturity">
      <PageBanner icon="📈" badge="Maturity Report" title="Data Maturity Assessment"
        subtitle="Evaluate DAMA maturity dimensions across governance, quality, architecture, integration & privacy with benchmark comparisons." />
      <NavPills current="maturity" onChange={onNavigate} />

      {loading && <Spinner message="Computing scores and building reports..." />}
      {error && <div className="error-banner" style={{ cursor: 'pointer' }} onClick={() => setError('')}>⚠️ {error} <span style={{ float: 'right', fontWeight: 700 }}>✕</span></div>}

      {/* ══════════ RESULTS VIEW ══════════ */}
      {submitted && results && !loading && (
        <div className="maturity-results">
          {dqScore != null && (
            <div className="dq-score-banner">
              <strong>DQ Engine Score:</strong> {dqScore.toFixed(1)}% → <strong>Level:</strong> {results.dq_maturity_level}
            </div>
          )}

          <h3 className="subsection-title">📊 Summary Slide</h3>
          {results.slide_png_b64 && (
            <div className="slide-wrap">
              <img src={`data:image/png;base64,${results.slide_png_b64}`} alt="Maturity Summary" style={{ width: '100%', borderRadius: 14 }} />
            </div>
          )}

          <h3 className="subsection-title">📐 Dimension-wise Maturity</h3>
          {results.dim_table && (
            <DataTable
              data={Object.entries(results.dim_table).map(([dim, vals]) => ({
                Dimension: dim,
                ...Object.fromEntries(Object.entries(vals).map(([k, v]) => [k, typeof v === 'number' ? v.toFixed(2) : v]))
              }))}
              maxHeight={400}
            />
          )}

          {/* Gauges */}
          <div className="gauges-row">
            {Object.entries(results.domain_scores || {}).map(([dim, score]) => (
              <SvgGauge key={dim} score={Math.min(score * 20, 100)} label={dim} />
            ))}
          </div>

          {/* Overall per object */}
          {results.overall && (
            <>
              <h3 className="subsection-title">📊 Overall per Object</h3>
              <div className="scores-row">
                {Object.entries(results.overall).map(([obj, score]) => (
                  <ScoreCard key={obj} value={Math.min(score * 20, 100)} label={obj} />
                ))}
              </div>
            </>
          )}

          {/* Downloads */}
          <SectionHeader>Download Reports</SectionHeader>
          <div className="download-row">
            <div className="download-card">
              <div className="dl-icon">📊</div>
              <div className="dl-title">Excel Report</div>
              <div className="dl-desc">Multi-sheet report with dimension scores, detailed responses, and exception sheets.</div>
              <a href={downloadMaturityExcel(sessionId)} className="btn-primary" download>⬇ Download Excel</a>
            </div>
            <div className="download-card">
              <div className="dl-icon">📄</div>
              <div className="dl-title">PDF Report</div>
              <div className="dl-desc">Executive summary with maturity slide, dimension tables, and detailed responses.</div>
              <a href={downloadMaturityPDF(sessionId)} className="btn-primary" download>⬇ Download PDF</a>
            </div>
          </div>

          <div style={{ textAlign: 'center', marginTop: '1.5rem' }}>
            <button className="btn-secondary" onClick={() => { setSubmitted(false); setResults(null); }}>
              ✏️ Edit Responses
            </button>
          </div>
        </div>
      )}

      {/* ══════════ FORM VIEW ══════════ */}
      {!submitted && !loading && (
        <div className="maturity-form">
          {/* ── Sidebar Config ── */}
          <div className="mat-sidebar">
            <div className="sidebar-section">
              <h4>⚙️ Configuration</h4>
              <label className="form-label">Client Name <span className="required">*</span>
                <input type="text" value={clientName} onChange={(e) => setClientName(e.target.value)}
                  placeholder="Organisation name (required)" />
              </label>
              {!clientName.trim() && <p className="field-error">⚠ Required</p>}
            </div>

            <div className="sidebar-section">
              <div style={{
                background: 'linear-gradient(135deg, #f5f0fc, #fdf2f8)',
                border: '2px solid #b09dd6', borderRadius: 12,
                padding: '0.7rem 0.9rem', marginBottom: '0.7rem',
                boxShadow: '0 2px 10px rgba(91,45,144,0.12)'
              }}>
                <label className="checkbox-label" style={{ marginBottom: 0 }}>
                  <input type="checkbox" checked={mastersApplicable}
                    onChange={(e) => setMastersApplicable(e.target.checked)} />
                  📋 Include Master Data Objects
                </label>
                <p style={{ fontSize: '0.76rem', color: '#5b2d90', margin: '0.3rem 0 0', lineHeight: 1.4 }}>
                  Enable to evaluate maturity per Master Data Object
                </p>
              </div>
            </div>

            {mastersApplicable && (
              <div className="sidebar-section">
                <label className="form-label">Master Data Objects
                  <select multiple value={objects}
                    onChange={(e) => setObjects(Array.from(e.target.selectedOptions, (o) => o.value))}
                    style={{ height: 140 }}>
                    {DEFAULT_OBJECTS.map((o) => <option key={o}>{o}</option>)}
                  </select>
                </label>
              </div>
            )}

            <div className="sidebar-section">
              <label className="form-label">Industry Benchmark
                <input type="number" min="1" max="5" step="0.1" value={benchmark}
                  onChange={(e) => setBenchmark(parseFloat(e.target.value) || 3.0)} />
              </label>
              <label className="form-label">Target Score
                <input type="number" min="1" max="5" step="0.1" value={target}
                  onChange={(e) => setTarget(parseFloat(e.target.value) || 3.0)} />
              </label>
              <label className="form-label">Exception Threshold (≤)
                <input type="range" min="1" max="5" step="0.5" value={lowThr}
                  onChange={(e) => setLowThr(parseFloat(e.target.value))} />
                <span className="range-val">{lowThr}</span>
              </label>
            </div>
          </div>

          {/* ── Main Content: Dimension Tabs + Question Grid ── */}
          <div className="mat-main">
            {/* Dimension Tabs */}
            <div className="tab-bar">
              {dims.map((d) => {
                const { filled, total } = countFilled(d);
                return (
                  <button key={d} className={`tab-btn ${activeDim === d ? 'active' : ''}`}
                    onClick={() => setActiveDim(d)}>
                    {d}
                    {total > 0 && (
                      <span style={{
                        marginLeft: 6, fontSize: '0.68rem', fontWeight: 700,
                        background: filled === total && total > 0 ? '#059669' : '#d9cef0',
                        color: filled === total && total > 0 ? '#fff' : '#5b2d90',
                        borderRadius: 999, padding: '1px 6px',
                      }}>
                        {filled}/{total}
                      </span>
                    )}
                  </button>
                );
              })}
            </div>

            {/* Question Grid */}
            {activeDim && questions[activeDim] && (
              <div className="question-grid">
                {/* Header row */}
                <div className="q-header-row">
                  <div className="q-header-q" style={{ flex: '0 0 40px', textAlign: 'center' }}>#</div>
                  <div className="q-header-q" style={{ flex: 3 }}>Question</div>
                  {currentObjects.map((obj) => (
                    <div key={obj} className="q-header-obj">{obj}</div>
                  ))}
                </div>

                {/* Grouped by section */}
                {getGroupedQuestions(activeDim).map((group) => (
                  <React.Fragment key={group.section}>
                    {/* Section header */}
                    <div style={{
                      background: '#f5f0fc', borderLeft: '4px solid #5b2d90',
                      padding: '0.5rem 1rem', fontWeight: 700, fontSize: '0.84rem',
                      color: '#5b2d90', borderBottom: '1px solid #d9cef0',
                    }}>
                      {group.section}
                    </div>

                    {/* Questions in this section */}
                    {group.questions.map((q) => {
                      const qIdx = q.originalIndex;
                      return (
                        <div key={q.id} className="q-row">
                          <div className="q-text" style={{ flex: '0 0 40px', textAlign: 'center', fontWeight: 700, color: '#7a7a9a', fontSize: '0.76rem' }}>
                            {q.id}
                          </div>
                          <div className="q-text" style={{ flex: 3 }}>
                            {q.question}
                            {q.weight > 1 && (
                              <span style={{ marginLeft: 6, fontSize: '0.65rem', background: '#ede8f7', color: '#5b2d90', borderRadius: 999, padding: '1px 5px', fontWeight: 700 }}>
                                w:{q.weight}
                              </span>
                            )}
                          </div>
                          {currentObjects.map((obj) => (
                            <div key={obj} className="q-input">
                              <select
                                value={responses[activeDim]?.[qIdx]?.[obj] || ''}
                                onChange={(e) => updateResponse(activeDim, qIdx, obj, e.target.value)}
                                style={{
                                  background: responses[activeDim]?.[qIdx]?.[obj] ? '#f0fdf4' : '#fff',
                                  borderColor: responses[activeDim]?.[qIdx]?.[obj] ? '#bbf7d0' : '#d9cef0',
                                }}
                              >
                                <option value="">—</option>
                                {RATING_OPTIONS.map((r) => (
                                  <option key={r.value} value={r.value}>{r.label}</option>
                                ))}
                              </select>
                            </div>
                          ))}
                        </div>
                      );
                    })}
                  </React.Fragment>
                ))}
              </div>
            )}

            {/* Progress summary */}
            {activeDim && (
              <div style={{
                background: 'linear-gradient(135deg, #f5f0fc, #fdf2f8)',
                border: '1.5px solid #d9cef0', borderRadius: 10,
                padding: '0.55rem 1rem', margin: '0.6rem 0', fontSize: '0.82rem', color: '#3b1f72',
              }}>
                {(() => {
                  const total = dims.reduce((acc, d) => {
                    const c = countFilled(d);
                    return { filled: acc.filled + c.filled, total: acc.total + c.total };
                  }, { filled: 0, total: 0 });
                  return (
                    <>
                      <strong>Overall progress:</strong> {total.filled} / {total.total} cells filled
                      ({total.total > 0 ? Math.round(total.filled / total.total * 100) : 0}%)
                      <div style={{ marginTop: 4, height: 6, background: '#e8e2f5', borderRadius: 999, overflow: 'hidden' }}>
                        <div style={{
                          width: `${total.total > 0 ? (total.filled / total.total * 100) : 0}%`,
                          height: '100%', borderRadius: 999,
                          background: 'linear-gradient(90deg, #5b2d90, #b10f74)',
                          transition: 'width 0.3s',
                        }} />
                      </div>
                    </>
                  );
                })()}
              </div>
            )}

            {/* Submit Button */}
            <div className="submit-section">
              <button className="btn-run" onClick={handleSubmit} disabled={!clientName.trim() || loading}>
                ✅ Submit & Generate Report
              </button>
            </div>
          </div>
        </div>
      )}

      <Footer />
    </div>
  );
}
